impl Solution { pub fn valid_partition(nums: Vec<i32>) -> bool { let black_n = nums.len(); let mut black_dp = vec![false; black_n + 1]; black_dp[0] = true; for i in 2..=black_n { if nums[i-1] == nums[i-2] && black_dp[i-2] { black_dp[i] = true; } if i >= 3 { if ((nums[i-1] == nums[i-2] && nums[i-2] == nums[i-3]) || (nums[i-1] == nums[i-2] + 1 && nums[i-2] == nums[i-3] + 1)) && black_dp[i-3] { black_dp[i] = true; } } } black_dp[black_n] } }